import sys, json
content = sys.stdin.read()
depth = 0; start = None; objects = []
for i, c in enumerate(content):
    if c == '{' and depth == 0: start = i
    if c == '{': depth += 1
    elif c == '}':
        depth -= 1
        if depth == 0: objects.append(content[start:i+1])
d = json.loads(objects[-1])
json.dump(d, open('after-cpm-packages.json', 'w'), indent=2)

# Compare
baseline = json.load(open('baseline-packages.json'))
after = d

def get_pkg_map(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

before_map = get_pkg_map(baseline)
after_map = get_pkg_map(after)

print('=== CHANGES ===')
changes = False
for key in sorted(set(list(before_map.keys()) + list(after_map.keys()))):
    bv = before_map.get(key, 'N/A')
    av = after_map.get(key, 'N/A')
    if bv != av:
        print(f'  {key[0]} | {key[1]} | {bv} -> {av}')
        changes = True
if not changes:
    print('  (no unexpected changes beyond intended alignment)')

print()
print('=== UNCHANGED ===')
for key in sorted(before_map.keys()):
    bv = before_map[key]
    av = after_map.get(key, 'N/A')
    if bv == av:
        print(f'  {key[0]} | {key[1]} | {bv}')
"

